<?php
declare(strict_types=1);
if($path!=='/admin/mail')return;if(!(user()['is_admin']??false)){http_response_code(403);exit('Forbidden');}
if($method==='POST'){
    verify_csrf();$transport=post('mail_transport')==='smtp'?'smtp':'local';$encryption=in_array(post('smtp_encryption'),['none','tls','ssl'],true)?post('smtp_encryption'):'tls';$values=['mail_transport'=>$transport,'mail_from_address'=>trim((string)post('mail_from_address')),'mail_from_name'=>trim((string)post('mail_from_name')),'smtp_host'=>trim((string)post('smtp_host')),'smtp_port'=>(string)max(1,min(65535,(int)post('smtp_port'))),'smtp_encryption'=>$encryption,'smtp_username'=>trim((string)post('smtp_username'))];if(post('smtp_password')!=='')$values['smtp_password_enc']=encrypt_secret((string)post('smtp_password'));$stmt=db()->prepare('INSERT INTO app_settings(setting_key,setting_value) VALUES(?,?) ON DUPLICATE KEY UPDATE setting_value=VALUES(setting_value)');foreach($values as $key=>$value)$stmt->execute([$key,$value]);audit('update','mail_settings',null,['transport'=>$transport,'host'=>$values['smtp_host'],'password_changed'=>isset($values['smtp_password_enc'])]);
    if(post('action')==='test'){$to=trim((string)post('test_email'));try{if(!crm_send_email($to,app_setting('app_name','OpenCRM').' email test',"This is a test email from ".app_setting('app_name','OpenCRM').".\n\nIf you received it, the mail transport is working."))throw new RuntimeException('The transport did not accept the message.');flash('success','Test email accepted for delivery.');app_log('info','Test email sent',['recipient'=>$to,'transport'=>$transport]);}catch(Throwable $e){flash('error','Test email failed: '.$e->getMessage());app_log('error','Test email failed',['recipient'=>$to,'transport'=>$transport,'error'=>$e->getMessage()]);}}else flash('success','Mail settings saved.');redirect('/admin/mail');
}
$settings=app_settings();layout('Mail settings',function()use($settings){?><div class="actions"><h1 style="margin:0">Mail settings</h1><span class="spacer"></span><a class="btn secondary" href="/admin/settings">Application settings</a></div><form class="card" method="post"><input type="hidden" name="_csrf" value="<?=csrf()?>"><h2>Delivery transport</h2><div class="form-grid"><label>Transport<select name="mail_transport"><option value="local" <?=$settings['mail_transport']==='local'?'selected':''?>>Local sendmail</option><option value="smtp" <?=$settings['mail_transport']==='smtp'?'selected':''?>>External SMTP</option></select><span class="muted">Local delivery requires a configured mail agent on this server.</span></label><div></div><label>From email<input type="email" name="mail_from_address" value="<?=e($settings['mail_from_address'])?>" placeholder="notifications@yourdomain.com" required></label><label>From name<input name="mail_from_name" value="<?=e($settings['mail_from_name']?:$settings['app_name'])?>"></label></div><section id="smtp-fields"><h2>SMTP connection</h2><div class="form-grid"><label>SMTP host<input name="smtp_host" value="<?=e($settings['smtp_host'])?>" placeholder="smtp.example.com"></label><label>Port<input type="number" name="smtp_port" min="1" max="65535" value="<?=e($settings['smtp_port'])?>"></label><label>Encryption<select name="smtp_encryption"><option value="tls" <?=$settings['smtp_encryption']==='tls'?'selected':''?>>STARTTLS</option><option value="ssl" <?=$settings['smtp_encryption']==='ssl'?'selected':''?>>SSL/TLS</option><option value="none" <?=$settings['smtp_encryption']==='none'?'selected':''?>>None</option></select></label><label>Username<input name="smtp_username" value="<?=e($settings['smtp_username'])?>" autocomplete="off"></label><label>Password<input type="password" name="smtp_password" autocomplete="new-password" placeholder="<?=e($settings['smtp_password_enc']?'Stored — leave blank to keep':'Enter SMTP password')?>"><span class="muted">Encrypted before it is stored.</span></label></div></section><hr><h2>Test delivery</h2><label>Send test to<input type="email" name="test_email" placeholder="you@example.com"></label><div class="actions"><button name="action" value="save">Save mail settings</button><button class="secondary" name="action" value="test">Save and send test</button></div></form><script>const transport=document.querySelector('[name=mail_transport]'),smtp=document.querySelector('#smtp-fields');function toggleMail(){smtp.hidden=transport.value!=='smtp'}transport.addEventListener('change',toggleMail);toggleMail()</script><?php });exit;
